84: 	txn := k.KV.Txn(ctx).If(
85: 		clientv3.Compare(clientv3.ModRevision(key), "=", expectedRevision),
86: 	).Then(
87: 		clientv3.OpPut(key, string(value), clientv3.WithLease(opts.LeaseID)),
88: 	)
89: 
90: 	if opts.GetOnFailure {
91: 		txn = txn.Else(clientv3.OpGet(key))
92: 	}
93: 
94: 	txnResp, err := txn.Commit()
95: 	if err != nil {
96: 		return resp, err
97: 	}
98: 	resp.Succeeded = txnResp.Succeeded
99: 	resp.Revision = txnResp.Header.Revision
100: 	if opts.GetOnFailure && !txnResp.Succeeded {
101: 		if len(txnResp.Responses) == 0 {
102: 			return resp, fmt.Errorf("invalid OptimisticPut response: %v", txnResp.Responses)
103: 		}
104: 		resp.KV = kvFromTxnResponse(txnResp.Responses[0])
105: 	}
106: 	return resp, nil
107: }
